// Prepare Portal lead data for storage
const lead = $input.first().json;
const enrichmentData = JSON.parse($node['AI Community Analysis'].json.choices[0].message.content || '{}');
const userData = $node['Portal Validation & Setup'].json;

return {
  runId: userData.runId,
  clientType: 'portal',
  name: enrichmentData.fullName || lead.name,
  email: enrichmentData.email || lead.email || '',
  phone: enrichmentData.phone || lead.phone || '',
  organization: enrichmentData.organization || lead.organization,
  title: enrichmentData.title || lead.title,
  location: enrichmentData.location || lead.location,
  linkedinUrl: lead.linkedinUrl || '',
  websiteUrl: lead.websiteUrl || '',

  // Community-specific data
  community: 'Israeli/Jewish',
  hebrewSkills: enrichmentData.hebrewSkills || 'unknown',
  communityInvolvement: JSON.stringify(enrichmentData.communityInvolvement || []),
  culturalInterests: JSON.stringify(enrichmentData.culturalInterests || []),

  // Contact and engagement
  socialMediaProfiles: JSON.stringify(enrichmentData.socialMediaProfiles || []),
  engagementOpportunities: JSON.stringify(enrichmentData.engagementOpportunities || []),

  // Metadata
  source: lead.source,
  enrichmentQuality: enrichmentData.confidence || 'medium',
  createdAt: new Date().toISOString(),
  status: 'enriched',
  targetLocation: userData.targetLocation
};

// Create Portal-specific CSV export
const leads = $input.first().json;
const userData = $node['Portal Validation & Setup'].json;

// CSV Headers for Portal leads
const headers = [
  'Name',
  'Email',
  'Phone',
  'Organization',
  'Title',
  'Location',
  'LinkedIn URL',
  'Website URL',
  'Community',
  'Hebrew Skills',
  'Community Involvement',
  'Cultural Interests',
  'Social Media Profiles',
  'Engagement Opportunities',
  'Source',
  'Quality Score'
];

// Create CSV content
let csvContent = headers.join(',') + '\n';

leads.forEach(lead => {
  const row = [
    lead.name || '',
    lead.email || '',
    lead.phone || '',
    `"${(lead.organization || '').replace(/"/g, '""')}"`,
    `"${(lead.title || '').replace(/"/g, '""')}"`,
    lead.location || '',
    lead.linkedinUrl || '',
    lead.websiteUrl || '',
    lead.community || '',
    lead.hebrewSkills || '',
    `"${(lead.communityInvolvement || '').replace(/"/g, '""')}"`,
    `"${(lead.culturalInterests || '').replace(/"/g, '""')}"`,
    `"${(lead.socialMediaProfiles || '').replace(/"/g, '""')}"`,
    `"${(lead.engagementOpportunities || '').replace(/"/g, '""')}"`,
    lead.source || '',
    lead.enrichmentQuality || ''
  ];
  csvContent += row.join(',') + '\n';
});

// Convert to base64
const base64 = Buffer.from(csvContent).toString('base64');

return {
  csvContent,
  base64,
  fileName: `portal_${userData.targetLocation}_leads_${userData.runId}.csv`,
  leadCount: leads.length,
  runId: userData.runId,
  clientType: 'portal',
  targetLocation: userData.targetLocation,
  userEmail: userData.clientInfo?.email || 'portal@local-il.com',
  userName: userData.clientInfo?.name || 'Portal Team'
};

